using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int n, a[35][35];
int fx[4][2] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
struct pos
{
	int x, y;
	pos(int ax = 0, int ay = 0)
	{
		x = ax;
		y = ay;
	}
};
void bfs(int x, int y)
{
	queue<pos>q;
	if (a[x][y])return;
	a[x][y] = 3;
	q.push(pos(x, y));
	while (!q.empty())
	{
		pos now = q.front();
		q.pop();
		for (int i = 0; i < 4; i++)
		{
			int xx = now.x + fx[i][0];
			int yy = now.y + fx[i][1];
			if (xx < 1 || xx > n || yy < 1 || yy > n)continue;
			if (a[xx][yy])continue;
			a[xx][yy] = 3;
			q.push(pos(xx, yy));
		}
	}
}
int main(void)
{
	cin >> n;
	for (int i = 1; i <= n; i++)
		for (int j = 1; j <= n; j++)
			cin >> a[i][j];
	for (int i = 1; i <= n; i++)bfs(1, i);
	for (int i = 1; i <= n; i++)bfs(n, i);
	for (int i = 1; i <= n; i++)bfs(i, 1);
	for (int i = 1; i <= n; i++)bfs(i, n);
	for (int i = 1; i <= n; i++)
	{
		for (int j = 1; j <= n; j++)
		{
			if (a[i][j] == 3)cout << 0 << ' ';
			else if (a[i][j] == 0)
				cout << 2 << ' ';
			else cout << 1 << ' ';
		}
		cout << endl;
	}
	return false;
}
